module RefModule(
    input clk,
    input rst,
    input [3:0] bin,
    output [3:0] gray
);reg [3:0] obf_gray_reg;

always @(posedge clk) begin
    if (rst) begin
        obf_gray_reg <= 4'b0;
    end else begin
        obf_gray_reg <= bin ^ (bin >> 1);
    end
end

assign gray = obf_gray_reg;

endmodule
